const item = $input.first().json;
const negRatio = item.negative_ratio || 0;
const vulnAreas = item.vulnerability_areas || [];
const topComplaints = item.top_complaints || [];
// Composite vulnerability score
const ratioScore = negRatio * 40;
const areaScore = Math.min(vulnAreas.length * 10, 30);
const complaintScore = Math.min(topComplaints.length * 6, 30);
const vulnerabilityIndex = Math.round(ratioScore + areaScore + complaintScore);
const exploitability = vulnerabilityIndex >= 70 ? 'high' : vulnerabilityIndex >= 40 ? 'medium' : 'low';
return [{ json: { ...item, vulnerability_index: vulnerabilityIndex,
  exploitability: exploitability, attack_vectors: vulnAreas.slice(0, 3) } }];
